# Generated by google (gemini-2.5-flash)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: '', description: 'Custom build command to execute (e.g., mvn clean install). Leave empty to skip this step.')
        string(name: 'TEST_COMMAND', defaultValue: '', description: 'Custom test command to execute (e.g., mvn test). Leave empty to skip this step.')
        string(name: 'DEPLOY_COMMAND', defaultValue: '', description: 'Custom deployment command to execute (e.g., docker push my-image). Leave empty to skip this step.')
    }

    stages {
        stage('Build') {
            steps {
                script {
                    if (params.BUILD_COMMAND && params.BUILD_COMMAND.trim() != '') {
                        echo "Executing custom build command: ${params.BUILD_COMMAND}"
                        sh params.BUILD_COMMAND
                    } else {
                        echo "BUILD_COMMAND parameter is empty. Skipping build step."
                    }
                }
            }
        }

        stage('Test') {
            steps {
                script {
                    if (params.TEST_COMMAND && params.TEST_COMMAND.trim() != '') {
                        echo "Executing custom test command: ${params.TEST_COMMAND}"
                        sh params.TEST_COMMAND
                    } else {
                        echo "TEST_COMMAND parameter is empty. Skipping test step."
                    }
                }
            }
        }

        stage('Deploy') {
            steps {
                script {
                    if (params.DEPLOY_COMMAND && params.DEPLOY_COMMAND.trim() != '') {
                        echo "Executing custom deployment command: ${params.DEPLOY_COMMAND}"
                        sh params.DEPLOY_COMMAND
                    } else {
                        echo "DEPLOY_COMMAND parameter is empty. Skipping deployment step."
                    }
                }
            }
        }
    }
}